// =====================================================
// 7. FIX HOSPITALITY GROUPS TO BE CITY-AWARE
// =====================================================
// The hospitalityGroupsHTML function needs to filter groups by city
html = html.replace(
  /hospitalityGroupsHTML\(\)\{/,
  `hospitalityGroupsHTML(){
    // NYC groups
    const nycGroupNames = ['Major Food Group','Union Square Hospitality (Danny Meyer)','Keith McNally','Unapologetic Foods','Rita Sodi & Jody Williams','Momofuku (David Chang)','NoHo Hospitality (Andrew Carmellini)','Quality Branded'];
    const dallasGroupNames = ['Harwood Hospitality Group','Vandelay Hospitality','Duro Hospitality','Travis Street Hospitality','FB Society','Milkshake Concepts','Fox Restaurant Concepts','Major Food Group','M Crowd Restaurant Group'];
    const cityGroups = (S.city||'Dallas')==='New York' ? nycGroupNames : dallasGroupNames;
    const filteredGroups = {};
    for(const name of cityGroups) {
      if(HOSPITALITY_GROUPS[name]) filteredGroups[name] = HOSPITALITY_GROUPS[name];
    }
    const _HG = filteredGroups;
    // Original function continues but uses _HG instead of HOSPITALITY_GROUPS`
);

// Replace HOSPITALITY_GROUPS references inside hospitalityGroupsHTML with _HG
// Find the function body and do targeted replacements
const hgFnStart = html.indexOf('hospitalityGroupsHTML(){');
const hgFnEnd = html.indexOf('\n  },\n', hgFnStart + 500);
if(hgFnEnd > hgFnStart) {
  let fnBody = html.substring(hgFnStart, hgFnEnd);
  // Count occurrences
  const count = (fnBody.match(/HOSPITALITY_GROUPS/g) || []).length;
  // Replace all HOSPITALITY_GROUPS with _HG inside this function EXCEPT the first definition block
  // We need to be careful -- only replace references that use it as data source
  fnBody = fnBody.replace(/Object\.keys\(HOSPITALITY_GROUPS\)/g, 'Object.keys(_HG)');
  fnBody = fnBody.replace(/Object\.entries\(HOSPITALITY_GROUPS\)/g, 'Object.entries(_HG)');
  fnBody = fnBody.replace(/HOSPITALITY_GROUPS\[/g, '_HG[');
  html = html.substring(0, hgFnStart) + fnBody + html.substring(hgFnEnd);
  console.log('Fixed hospitality groups (city-aware), replaced', count, 'references');
}

